import{_ as o,o as t,c as l,a3 as r}from"./chunks/framework.d0TBG0Rg.js";const u=JSON.parse('{"title":"免责声明 (舞萌成绩同步)","description":"舞萌 DX 成绩同步助手的免责声明，使用前请务必阅读。","frontmatter":{"title":"免责声明 (舞萌成绩同步)","description":"舞萌 DX 成绩同步助手的免责声明，使用前请务必阅读。"},"headers":[],"relativePath":"disclaimer.md","filePath":"disclaimer.md"}'),i={name:"disclaimer.md"};function e(n,a,s,d,h,c){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="免责声明-舞萌成绩同步" tabindex="-1">免责声明 (舞萌成绩同步) <a class="header-anchor" href="#免责声明-舞萌成绩同步" aria-label="Permalink to &quot;免责声明 (舞萌成绩同步)&quot;">​</a></h1><blockquote><p>更新日期：2026年4月6日</p></blockquote><p>在使用《舞萌DX 成绩同步助手》插件（以下简称“本插件”）前，请您务必审慎阅读、充分理解并同意本声明的全部内容。您的使用行为将被视为对本声明条款的无条件接受。</p><h2 id="第一章-总则与性质" tabindex="-1">第一章：总则与性质 <a class="header-anchor" href="#第一章-总则与性质" aria-label="Permalink to &quot;第一章：总则与性质&quot;">​</a></h2><ol><li>本插件是由独立开发者提供的第三方工具，旨在协助用户将《舞萌DX》在街机端的游玩记录，同步至指定的非官方查分器平台。</li><li>本插件与《舞萌DX》（maimai DX）的版权方、发行商、运营方及其关联公司无任何隶属、授权或合作关系，并非官方服务的一部分。</li></ol><h2 id="第二章-用户义务与安全规范" tabindex="-1">第二章：用户义务与安全规范 <a class="header-anchor" href="#第二章-用户义务与安全规范" aria-label="Permalink to &quot;第二章：用户义务与安全规范&quot;">​</a></h2><ol><li><strong>凭证管理义务</strong>：您有义务妥善保管您个人的查分器账号令牌（Token）或OAuth授权码。该凭证是您个人账号的唯一电子钥匙，任何泄露都可能导致您的数据被他人获取或篡改。您应独自承担凭证保管不善的一切后果。</li><li><strong>操作环境要求</strong>：在使用“导入成绩”功能时，您必须提供游戏登录二维码文本。此文本具备瞬时登录权限，<strong>建议您在安全环境中进行操作</strong>。在公开或半公开群组中使用此功能，即视为您自愿承担极高的账号安全风险。</li><li><strong>数据处理与存储声明</strong>：针对“设置类型1”功能，为了实现后续成绩的自动获取，系统将对您的游戏用户标识（UserId）进行加密处理后存储于服务器。该存储行为仅用于维持自动查询服务的连续性，系统不会存储您的登录凭据（Token）、二维码信息及原始游戏明文数据。</li></ol><h2 id="第三章-核心功能说明与固有风险" tabindex="-1">第三章：核心功能说明与固有风险 <a class="header-anchor" href="#第三章-核心功能说明与固有风险" aria-label="Permalink to &quot;第三章：核心功能说明与固有风险&quot;">​</a></h2><ol><li><strong>工作模式选择</strong>： <ul><li><strong>模式一（仅同步）</strong>：仅上传成绩到查分器（首次使用保存UserId，后续自动获取）</li><li>注意：通过对手API获取的成绩不包含曲目FC/FS状态</li><li><strong>模式二（同步后登出）</strong>：上传成绩到查分器，并自动登出。</li></ul></li><li><strong>服务可用性</strong>：为保障系统稳定，插件所依赖的后端服务将在 <strong>每日 00:00 至 11:00</strong> 进行例行维护，此期间所有功能将暂停。此属于计划的正常服务间歇，并非程序错误或故障。</li></ol><h2 id="第四章-风险确认与责任豁免" tabindex="-1">第四章：风险确认与责任豁免 <a class="header-anchor" href="#第四章-风险确认与责任豁免" aria-label="Permalink to &quot;第四章：风险确认与责任豁免&quot;">​</a></h2><ol><li><strong>您确认已充分知悉</strong>：使用非官方认可的工具或方法访问游戏服务，其行为本身即存在被游戏运营方通过技术手段识别，并进而对您的游戏账号采取限制、封禁等处罚措施的不可消除的潜在风险。</li><li><strong>责任完全豁免</strong>：鉴于上述固有风险及互联网服务的复杂性，因您使用本插件而直接或间接引发的任何形式的损害后果（包括但不限于：游戏账号封停、游戏内数据（如Rating、游玩记录）异常或丢失、第三方查分器数据错误、个人隐私信息泄露以及由此带来的任何精神或经济损失），均由您本人承担全部责任。插件开发者、贡献者及关联方对此不承担任何性质的民事、行政或刑事责任。</li></ol><h2 id="第五章-第三方服务与声明更新" tabindex="-1">第五章：第三方服务与声明更新 <a class="header-anchor" href="#第五章-第三方服务与声明更新" aria-label="Permalink to &quot;第五章：第三方服务与声明更新&quot;">​</a></h2><ol><li>本插件的功能实现深度依赖于“水鱼查分器”、“落雪咖啡屋”等第三方平台提供的应用程序接口（API）。若因上述第三方接口变更、服务中断、策略调整或终止运营导致插件功能失效，开发者无义务也未必能保证提供永久解决方案。</li><li>开发者保留随时更新本声明的权利。更新后的声明将在相关页面公布后立即生效，请您定期查阅。</li></ol>',13)])])}const m=o(i,[["render",e]]);export{u as __pageData,m as default};
